<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>2048 – Dark Theme</title>
<style>
  html,body{
    height:100%;margin:0;padding:0;
    background:#1e1e1e;
    color:#fff;
    font-family:Arial,Helvetica,sans-serif;
    display:flex;align-items:center;justify-content:center;
  }
  #container{
    text-align:center;
  }
  #score{
    font-size:1.5rem;
    margin-bottom:0.5rem;
  }
  #reset{
    margin-bottom:1rem;
    padding:0.5rem 1rem;
    font-size:1rem;
    cursor:pointer;
    background:#555;
    border:none;
    color:#fff;
    border-radius:4px;
  }
  #board{
    display:grid;
    grid-template-columns:repeat(4,80px);
    grid-gap:8px;
    background:#333;
    padding:8px;
    border-radius:8px;
    width:max-content;
    margin:auto;
  }
  .tile{
    width:80px;height:80px;
    background:#2b2b2b;
    border-radius:6px;
    display:flex;
    align-items:center;
    justify-content:center;
    font-size:2rem;
    font-weight:bold;
    color:#bbb;
  }
  .tile.val2   {background:#eee4da;color:#776e65;}
  .tile.val4   {background:#ede0c8;color:#776e65;}
  .tile.val8   {background:#f2b179;color:#f9f6f2;}
  .tile.val16  {background:#f59563;color:#f9f6f2;}
  .tile.val32  {background:#f67c5f;color:#f9f6f2;}
  .tile.val64  {background:#f65e3b;color:#f9f6f2;}
  .tile.val128 {background:#edcf72;color:#f9f6f2;}
  .tile.val256 {background:#edcc61;color:#f9f6f2;}
  .tile.val512 {background:#edc850;color:#f9f6f2;}
  .tile.val1024{background:#edc53f;color:#f9f6f2;}
  .tile.val2048{background:#edc22e;color:#f9f6f2;}
</style>
</head>
<body>
<div id="container">
  <div id="score">Score: 0</div>
  <button id="reset">New Game</button>
  <div id="board"></div>
</div>

<script>
(() => {
  const size = 4;
  let grid = [];
  let score = 0;

  const initGrid = () => {
    grid = Array.from({ length: size }, () => Array(size).fill(0));
  };

  const cloneGrid = g => g.map(row => row.slice());

  const gridsEqual = (a, b) => {
    for (let r = 0; r < size; r++) {
      for (let c = 0; c < size; c++) {
        if (a[r][c] !== b[r][c]) return false;
      }
    }
    return true;
  };

  const updateUI = () => {
    const board = document.getElementById('board');
    board.innerHTML = '';
    for (let r = 0; r < size; r++) {
      for (let c = 0; c < size; c++) {
        const val = grid[r][c];
        const tile = document.createElement('div');
        tile.className = 'tile';
        if (val) {
          tile.textContent = val;
          tile.classList.add('val' + val);
        }
        board.appendChild(tile);
      }
    }
    document.getElementById('score').textContent = 'Score: ' + score;
  };

  const addRandomTile = () => {
    const empty = [];
    for (let r = 0; r < size; r++) {
      for (let c = 0; c < size; c++) {
        if (grid[r][c] === 0) empty.push([r, c]);
      }
    }
    if (!empty.length) return;
    const [r, c] = empty[Math.floor(Math.random() * empty.length)];
    grid[r][c] = Math.random() < 0.9 ? 2 : 4;
  };

  const resetGame = () => {
    initGrid();
    score = 0;
    addRandomTile();
    addRandomTile();
    updateUI();
  };

  const slideAndMerge = line => {
    const filtered = line.filter(v => v !== 0);
    let mergedScore = 0;
    const merged = [];
    for (let i = 0; i < filtered.length; i++) {
      if (i + 1 < filtered.length && filtered[i] === filtered[i + 1]) {
        const newVal = filtered[i] * 2;
        merged.push(newVal);
        mergedScore += newVal;
        i++; // skip next
      } else {
        merged.push(filtered[i]);
      }
    }
    while (merged.length < size) merged.push(0);
    return { line: merged, inc: mergedScore };
  };

  const move = direction => {
    const before = cloneGrid(grid);
    let inc = 0;

    if (direction === 'left' || direction === 'right') {
      for (let r = 0; r < size; r++) {
        let line = grid[r].slice();
        if (direction === 'right') line.reverse();
        const { line: newLine, inc: lineInc } = slideAndMerge(line);
        inc += lineInc;
        grid[r] = direction === 'right' ? newLine.reverse() : newLine;
      }
    } else if (direction === 'up' || direction === 'down') {
      for (let c = 0; c < size; c++) {
        let line = [];
        for (let r = 0; r < size; r++) line.push(grid[r][c]);
        if (direction === 'down') line.reverse();
        const { line: newLine, inc: lineInc } = slideAndMerge(line);
        inc += lineInc;
        const final = direction === 'down' ? newLine.reverse() : newLine;
        for (let r = 0; r < size; r++) grid[r][c] = final[r];
      }
    }

    if (!gridsEqual(before, grid)) {
      score += inc;
      addRandomTile();
      updateUI();
      return true;
    }
    return false;
  };

  // expose API
  window.game = {
    size,
    reset: resetGame,
    move,
    board: () => cloneGrid(grid),
    setBoard: arr => {
      grid = arr.map(row => row.slice());
      updateUI();
    },
    score: () => score
  };

  // UI wiring
  document.addEventListener('DOMContentLoaded', () => {
    resetGame();
    document.getElementById('reset').addEventListener('click', resetGame);
    document.addEventListener('keydown', e => {
      const map = {
        ArrowLeft: 'left',
        ArrowRight: 'right',
        ArrowUp: 'up',
        ArrowDown: 'down'
      };
      if (map[e.key]) {
        e.preventDefault();
        move(map[e.key]);
      }
    });
  });
})();
</script>
</body>
</html>
